const lib = global.get('lib');
if (!lib || !lib.telemetry || typeof lib.telemetry.handleTelemetryMessage !== 'function') {
  node.status({ fill: 'red', shape: 'ring', text: 'telemetry API missing' });
  return [null, null, { payload: { error: 'TELEMETRY_API_MISSING' } }];
}

const telemetry = lib.telemetry;
const incoming = msg.payload && typeof msg.payload === 'object' && !Array.isArray(msg.payload)
  ? { ...msg, ...msg.payload }
  : msg;
const equipmentId = incoming.equipmentId || incoming.instance?.equipmentId || incoming._reader?.equipmentId || msg.equipmentId;
const stateKey = equipmentId ? `telemetryState:${equipmentId}` : null;
const state = stateKey ? (flow.get(stateKey) || telemetry.createTelemetryRuntimeState()) : telemetry.createTelemetryRuntimeState();

if (incoming.error && !equipmentId) {
  node.status({ fill: 'yellow', shape: 'ring', text: 'modbus transport error' });
  return [null, null, { payload: { error: incoming.error, source: 'modbus', incoming } }];
}

if (!equipmentId) {
  node.status({ fill: 'red', shape: 'ring', text: 'equipment missing' });
  return [null, null, { payload: { error: 'EQUIPMENT_ID_MISSING', incoming } }];
}

const asNodeRedMsg = (value) => {
  if (value == null) return null;
  if (typeof value === 'object' && !Array.isArray(value) && Object.prototype.hasOwnProperty.call(value, 'payload')) {
    return value;
  }
  return { payload: value };
};

const decorate = (value) => {
  const out = asNodeRedMsg(value);
  if (!out) return null;
  out.equipmentId = out.equipmentId || equipmentId;
  out.serverKey = out.serverKey || incoming.serverKey || incoming.instance?.serverKey || equipmentId;
  return out;
};

const envCfg = {
  CompilerMaxQty: 120,
  CompilerMaxSpan: 80,
  CompilerMaxHole: 4,
  PollFastMs: 250,
  PollNormalMs: 1000,
  PollSlowMs: 5000,
  MAX_IN_FLIGHT: 8,
  REQUEST_TIMEOUT_MS: 1500,
  MODBUS_ZERO_BASED: false,
  JITTER_MS: 0,
  RESPECT_TAG_CLAMP: true,
  SCALE_CLAMP_DEFAULT: false,
  SKIP_EMPTY_SAMPLES: false
};

try {
  const result = telemetry.handleTelemetryMessage(
    incoming,
    envCfg,
    state,
    (o1, o2, o3) => node.send([decorate(o1), decorate(o2), decorate(o3)])
  );

  if (stateKey) {
    flow.set(stateKey, result.state);
  }

  const statusText = `${equipmentId}:${incoming.cmd || (incoming._reader ? 'reply' : 'start')}`;
  node.status({ fill: 'green', shape: 'dot', text: statusText });

  return [decorate(result.out1), decorate(result.out2), decorate(result.out3)];
} catch (err) {
  node.status({ fill: 'red', shape: 'ring', text: `${equipmentId}:runtime threw` });
  return [null, null, { payload: { error: String(err), equipmentId } }];
}

const incoming = Array.isArray(msg.payload) ? msg.payload : [];
const inferEquipment = () => {
  if (msg.equipmentId) return msg.equipmentId;
  if (msg.payload && typeof msg.payload === 'object' && msg.payload.equipment) return msg.payload.equipment;
  for (const sample of incoming) {
    if (sample && typeof sample.tagID === 'string' && sample.tagID.includes('.')) {
      return sample.tagID.split('.')[0];
    }
  }
  return 'UNKNOWN';
};

const equipmentName = inferEquipment();
const legacyStore = global.get('NEW_telemetry') || {};
const modernStore = global.get('telemetry') || {};
const store = { ...legacyStore, ...modernStore };
const current = Array.isArray(store[equipmentName]) ? store[equipmentName] : [];
const byTag = {};

const toIsoTs = (value) => {
  if (typeof value === 'string' && value.trim()) {
    const parsed = new Date(value);
    if (!Number.isNaN(parsed.getTime())) return parsed.toISOString();
  }
  if (typeof value === 'number' && Number.isFinite(value)) {
    return new Date(value).toISOString();
  }
  return new Date().toISOString();
};

const normalizeFlag = (value) => {
  if (value === true) return 'Yes';
  if (value === false) return 'No';
  if (typeof value === 'string') {
    const norm = value.trim().toLowerCase();
    if (norm === 'yes' || norm === 'true') return 'Yes';
    if (norm === 'no' || norm === 'false' || norm === '') return 'No';
  }
  return 'No';
};

for (const sample of current) {
  if (sample && sample.tagID) byTag[sample.tagID] = sample;
}

for (const sample of incoming) {
  if (!sample || !sample.tagID) continue;
  const tagID = sample.tagID.includes('.')
    ? sample.tagID
    : `${equipmentName}.${sample.tagID}`;

  byTag[tagID] = {
    tagID,
    value: sample.value,
    timestamp: toIsoTs(sample.timestamp),
    alarm: normalizeFlag(sample.alarm),
    supportingTag: normalizeFlag(sample.supportingTag)
  };

  if (sample.enumLabel !== undefined) byTag[tagID].enumLabel = sample.enumLabel;
  if (sample.activeBits !== undefined) byTag[tagID].activeBits = sample.activeBits;
  if (sample.activeLabels !== undefined) byTag[tagID].activeLabels = sample.activeLabels;
  if (sample.rawValue !== undefined) byTag[tagID].rawValue = sample.rawValue;
}

store[equipmentName] = Object.values(byTag).sort((a, b) => a.tagID.localeCompare(b.tagID));
global.set('telemetry', store);
global.set('NEW_telemetry', store);

msg.payload = {
  equipment: equipmentName,
  count: store[equipmentName].length,
  NEW_telemetry: store[equipmentName]
};
return msg;

const requested = msg.equipmentId || msg.payload?.equipment || 'MBMU';
const store = global.get('NEW_telemetry') || global.get('telemetry') || {};
msg.payload = {
  equipment: requested,
  NEW_telemetry: Array.isArray(store[requested]) ? store[requested] : []
};
return msg;

const lib = global.get('lib');
if (!lib || !lib.telemetry || typeof lib.telemetry.buildSs40kLookup !== 'function') {
  node.status({ fill: 'red', shape: 'ring', text: 'ss40k API missing' });
  return { payload: { error: 'SS40K_API_MISSING' } };
}

const equipmentConfig = flow.get('telemetryEquipmentConfig') || {
  PCS: { profileName: 'Delta_280_ss40k', route: 'slot2' },
  MBMU: { profileName: 'MBMU_280_ss40k', route: 'slot1' }
};
const result = lib.telemetry.buildSs40kLookup(equipmentConfig);

global.set('ss40kLookup', result.lookup);
global.set('ss40kEquipmentToProfile', result.equipmentToProfile);
global.set('ss40kModelIndexMap', result.modelIndexMap);
flow.set('telemetryRouteMap', result.routeMap || flow.get('telemetryRouteMap') || {});

node.status({ fill: 'green', shape: 'dot', text: `${Object.keys(result.lookup).length} mapped tags` });
msg.payload = {
  lookupCount: Object.keys(result.lookup).length,
  equipmentToProfile: result.equipmentToProfile,
  routeMap: flow.get('telemetryRouteMap'),
  modelIndexMap: result.modelIndexMap,
  sample: Object.fromEntries(Object.entries(result.lookup).slice(0, 10))
};
return msg;

const lib = global.get('lib');
if (!lib || !lib.telemetry || typeof lib.telemetry.buildSs40kFixedPayloads !== 'function') {
  node.status({ fill: 'red', shape: 'ring', text: 'ss40k API missing' });
  return [null, { payload: { error: 'SS40K_API_MISSING' } }, null];
}

const lookup = global.get('ss40kLookup') || {};
const telemetry = global.get('NEW_telemetry') || global.get('telemetry') || {};
const config = flow.get('controlConfig') || global.get('controlConfig') || global.get('unifiedControlConfig') || {};
if (!Object.keys(lookup).length) {
  node.status({ fill: 'yellow', shape: 'ring', text: 'lookup missing' });
  return [null, { payload: { error: 'SS40K_LOOKUP_MISSING' } }, null];
}

const thingId = config?.cloud?.thingId || config?.cloud?.gsn || config?.site?.thingId || config?.site?.gsn || global.get('thingId') || '25000752';
const topic = config?.cloud?.telemetryTopic || `fort/v1/things/${thingId}/telem`;
const messages = lib.telemetry.buildSs40kFixedPayloads({ lookup, telemetry, topic, version: '3.0' });

node.status({ fill: 'green', shape: 'dot', text: `${messages.length} payloads` });
return [messages, null, { payload: messages.map((msg) => msg.ss40k) }];

msg.payload = {
  equipmentToProfile: global.get('ss40kEquipmentToProfile') || {},
  modelIndexMap: global.get('ss40kModelIndexMap') || {},
  lookup: global.get('ss40kLookup') || {}
};
return msg;

const routing = Object.assign({}, flow.get('telemetryRouteMap') || {});
const routeKey = msg.serverKey || msg.equipmentId || msg._reader?.equipmentId;
const target = routeKey ? routing[routeKey] : null;
const slot = target || routeKey;
const outputs = { slot1: 0, slot2: 1, slot3: 2, slot4: 3, slot5: 4, slot6: 5, MBMU: 0, PCS: 1, METER: 2, Meter: 2, Meter2: 3 };
const idx = outputs[slot];
if (idx !== undefined) {
  const out = new Array(7).fill(null);
  out[idx] = msg;
  return out;
}
node.status({ fill: 'yellow', shape: 'ring', text: `no route ${routeKey || '?'}` });
return [null, null, null, null, null, null, { payload: { error: 'NO_MODBUS_ROUTE', routeKey, target, routing } }];

const lib = global.get('lib');
if (!lib || !lib.telemetry || typeof lib.telemetry.buildSs40kLookup !== 'function') {
  node.status({ fill: 'red', shape: 'ring', text: 'telemetry API missing' });
  return [null, null, { payload: { error: 'TELEMETRY_API_MISSING' } }];
}

function asNumber(value, fallback) {
  const n = Number(value);
  return Number.isFinite(n) ? n : fallback;
}
function normalizeProfile(profile) {
  if (!profile) return '';
  const s = String(profile);
  if (s === 'udt_eGauge_V1') return 'eGauge_280_ss40k';
  return s;
}
function sourceProfile(source, fallback) {
  return normalizeProfile(source && (source.profileName || source.profile || source.modbusProfile)) || fallback;
}
function sourceIp(source, fallback) {
  return String((source && (source.ip || source.host || source.tcpHost)) || fallback || '127.0.0.1');
}
function sourcePort(source, fallback) {
  return asNumber(source && (source.port || source.tcpPort), fallback || 502);
}
function addReader(readers, reader) {
  if (!reader || !reader.equipmentId || !reader.profileName) return;
  if (readers.some((existing) => existing.equipmentId === reader.equipmentId)) return;
  readers.push({
    equipmentId: String(reader.equipmentId),
    profileName: normalizeProfile(reader.profileName),
    ip: String(reader.ip || reader.host || reader.tcpHost || '127.0.0.1'),
    port: asNumber(reader.port || reader.tcpPort, 502),
    unitId: asNumber(reader.unitId, 1),
    route: String(reader.route || reader.serverKey || reader.equipmentId),
    role: reader.role || undefined
  });
}
function defaultReaders(config) {
  const readers = [];
  const profile = String(config?.system?.systemProfile || 'eSpire280');
  const isMini = profile.startsWith('MINI-');
  const sources = config?.signalMapping?.sources || {};
  const metering = config?.metering || {};
  const pcsIp = config?.network?.controller?.modbusServer?.ip || '127.0.0.1';
  if (config?.telemetryReaders && Array.isArray(config.telemetryReaders)) {
    for (const reader of config.telemetryReaders) addReader(readers, reader);
    return readers;
  }
  for (const [equipmentId, source] of Object.entries(sources)) {
    addReader(readers, {
      equipmentId,
      profileName: sourceProfile(source, equipmentId === 'PCS' ? (isMini ? 'Sinexcel_Mini_PCS_ss40k' : 'Delta_280_ss40k') : 'eGauge_280_ss40k'),
      ip: sourceIp(source, equipmentId === 'PCS' ? pcsIp : metering.ip),
      port: sourcePort(source, 502),
      unitId: asNumber(source.unitId, 1),
      route: source.route || equipmentId,
      role: source.role
    });
  }
  if (isMini) {
    addReader(readers, { equipmentId: 'PCS', profileName: 'Sinexcel_Mini_PCS_ss40k', ip: pcsIp, route: 'PCS' });
    addReader(readers, { equipmentId: 'AMPACE', profileName: 'AMPACE_Mini_ss40k', ip: config?.battery?.ip || pcsIp, route: 'AMPACE' });
    addReader(readers, { equipmentId: 'Load', profileName: 'Sinexcel_Mini_Load_ss40k', ip: pcsIp, route: 'Load' });
    const segment = String(profile).split('-')[2];
    const dcPvKw = asNumber(segment, 0);
    const modules = Math.max(0, Math.min(3, Math.round(dcPvKw / 45)));
    for (let i = 1; i <= modules; i++) addReader(readers, { equipmentId: 'PVDC' + i, profileName: 'Sinexcel_Mini_PVDC_Module' + i + '_ss40k', ip: pcsIp, route: 'PVDC' + i });
  } else {
    addReader(readers, { equipmentId: 'PCS', profileName: 'Delta_280_ss40k', ip: pcsIp, route: 'PCS' });
    addReader(readers, { equipmentId: 'MBMU', profileName: 'MBMU_280_ss40k', ip: pcsIp, route: 'MBMU' });
    if (metering.ip) addReader(readers, { equipmentId: 'Meter', profileName: normalizeProfile(metering.modbusProfile || 'eGauge_280_ss40k'), ip: metering.ip, route: 'Meter' });
  }
  return readers;
}

const config = msg.controlConfig || msg.payload?.controlConfig || flow.get('controlConfig') || global.get('controlConfig') || global.get('unifiedControlConfig') || {};
const readers = defaultReaders(config).slice(0, 6);
if (!readers.length) {
  node.status({ fill: 'yellow', shape: 'ring', text: 'no telemetry readers' });
  return [null, null, { payload: { error: 'NO_TELEMETRY_READERS', configKeys: Object.keys(config || {}) } }];
}

const slotNames = ['slot1', 'slot2', 'slot3', 'slot4', 'slot5', 'slot6'];
const routeMap = {};
const equipmentConfig = {};
const compileMessages = [];
const startMessages = [];
const connectorMessages = [];
for (let i = 0; i < readers.length; i++) {
  const reader = readers[i];
  const slot = slotNames[i];
  routeMap[reader.route] = slot;
  routeMap[reader.equipmentId] = slot;
  equipmentConfig[reader.equipmentId] = { profileName: reader.profileName, route: slot };
  connectorMessages.push({
    slot,
    equipmentId: reader.equipmentId,
    payload: { connectorType: 'TCP', tcpHost: reader.ip, tcpPort: String(reader.port) }
  });
  compileMessages.push({
    payload: { cmd: 'compile', profileName: reader.profileName, instance: { equipmentId: reader.equipmentId, serverKey: reader.route, unitId: reader.unitId } },
    equipmentId: reader.equipmentId,
    serverKey: reader.route
  });
  startMessages.push({
    payload: { cmd: 'start', equipmentId: reader.equipmentId },
    equipmentId: reader.equipmentId,
    serverKey: reader.route
  });
}

const result = lib.telemetry.buildSs40kLookup(equipmentConfig);
global.set('ss40kLookup', result.lookup);
global.set('ss40kEquipmentToProfile', result.equipmentToProfile);
global.set('ss40kModelIndexMap', result.modelIndexMap);
global.set('telemetryReaderConfig', readers);
flow.set('telemetryRouteMap', routeMap);
flow.set('telemetryEquipmentConfig', equipmentConfig);
flow.set('telemetryReaderConfig', readers);

node.send([null, connectorMessages, { payload: { state: 'connectors-configured', readers, routeMap } }]);
for (const message of compileMessages) node.send([message, null, null]);
setTimeout(() => {
  for (const message of startMessages) node.send([message, null, null]);
}, 1500);

node.status({ fill: 'green', shape: 'dot', text: `${readers.length} reader(s), ${Object.keys(result.lookup).length} mapped tags` });
return [null, null, { payload: { state: 'telemetry-setup', readers, routeMap, lookupCount: Object.keys(result.lookup).length } }];

const slot = msg.slot || msg.route || msg.equipmentId;
const outputs = { slot1: 0, slot2: 1, slot3: 2, slot4: 3, slot5: 4, slot6: 5 };
const idx = outputs[slot];
if (idx === undefined) {
  node.status({ fill: 'yellow', shape: 'ring', text: `no connector slot ${slot || '?'}` });
  return [null, null, null, null, null, null, { payload: { error: 'NO_CONNECTOR_SLOT', slot, msg } }];
}
const out = new Array(7).fill(null);
out[idx] = msg;
return out;

const payload = msg.payload;
const timestamp = msg.timestamp || new Date().toISOString();

if (payload && typeof payload === 'object' && !Array.isArray(payload)) {
  for (const key of Object.keys(payload)) {
    const record = payload[key];
    if (record && typeof record === 'object' && !Array.isArray(record) && !record.timestamp) {
      record.timestamp = timestamp;
    }
  }
}

msg.topic = msg.topic || global.get('telemetryTopic') || 'fort/v1/things/25000752/telem';
msg.payload = payload;
msg.timestamp = timestamp;
msg.awsOutput = 'awsOutput';
return msg;
